  ('aboriginal-a5729396-moex-00584', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '關於合會中，會首之權利及義務，下列敘述何者錯誤？', '["主持標會及通知會員開會", "首期合會金不經投標，由會首取得", "無人出標時，原則上由會首決定何人得標", "代墊會款之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
