  ('aboriginal-a5729396-moex-00586', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列關於民法規定輔助宣告之敘述，何者正確？', '["法院應優先選定受輔助宣告人之配偶擔任輔助人", "受輔助宣告人之財產，由輔助人管理", "輔助開始時，輔助人應於二個月內開具財產清冊，並陳報法院", "輔助人得請求報酬，其數額由法院按其勞力及受監護人之資力酌定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00587', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列何種婚姻關係得撤銷？', '["結婚之證人並未親見親聞雙方當事人有結婚之真意", "婚姻之一方當事人年僅15歲", "四親等旁系血親之表姊與表弟間之婚姻", "有婚姻者，再與第三人結婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00588', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲乙之子女為丙，丁戊之子女為庚。丙庚結婚所生之子女為辛。辛與癸結婚後，辛與丙庚一同出遊遇 難，辛丙庚同時死亡。辛之遺產有新臺幣（下同）1,200萬元，應如何分配該繼承財產？', '["甲繼承100萬元", "丁繼承200萬元", "乙繼承300萬元", "癸繼承400萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00589', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '司法警察在下列情況下詢問犯罪嫌疑人所取得之自白，何者得作為證據？', '["於夜間未經受訊問人同意而詢問", "等候辯護人之時間已超過4小時後，辯護人尚未到場所為之詢問", "將犯罪嫌疑人解送至地方檢察署途中所為之詢問", "犯罪嫌疑人須由通譯傳譯，未等通譯4小時，通譯尚未到場前所為之詢問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00590', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲涉嫌竊盜鄰居乙之財物，為警逮捕到案。下列情形，何者有證據能力？', '["甲不耐疲勞轟炸，乃自白竊盜犯行", "甲已表示選任辯護人之意思，於等候甲選擇並聯繫辯護人之期間，員警仍加以詢問，被告因而自白 竊盜犯行", "甲出於自由意志自白竊盜犯行，且與事實相符", "乙以證人身分於檢察官訊問時作證，卻未具結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00591', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '刑事訴訟法第293條前段規定，審判非一次期日所能終結者，除有特別情形外，應於次日連續開庭。 此規定係落實下列何種原則？', '["繼續審理原則", "直接審理原則", "公開審理原則", "言詞審理原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00592', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '刑事案件被告之羈押，由何人負責審查決定？', '["法官", "檢察官", "司法警察官", "檢察總長"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00593', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '下列關於故意或過失之敘述，何者錯誤？', '["對於行為之處罰，應有故意或過失始可", "過失行為之處罰，應有法律之明文規定", "行為人按其情節應注意，並能注意，而不注意者，為故意", "行為人對於構成犯罪之事實，明知並有意使其發生者，為故意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
